import{_ as l,o as s,c as e,a2 as i,j as t}from"./chunks/framework.BWuWLRhz.js";const r="/assets/cases/xiaofangshu/deal-company-config-thumb.jpg",p="/assets/cases/xiaofangshu/deal-company-config.mp4",o="/assets/cases/xiaofangshu/store-staff-permission-thumb.jpg",d="/assets/cases/xiaofangshu/store-staff-permission.mp4",n="/assets/cases/xiaofangshu/building-config-thumb.jpg",h="/assets/cases/xiaofangshu/building-config.mp4",c="/assets/cases/xiaofangshu/building-attribute-switch-thumb.jpg",u="/assets/cases/xiaofangshu/building-attribute-switch.mp4",g="/assets/cases/xiaofangshu/upload-building-list-thumb.jpg",b="/assets/cases/xiaofangshu/upload-building-list.mp4",m="/assets/cases/xiaofangshu/vision-building-circle-thumb.jpg",f="/assets/cases/xiaofangshu/vision-building-circle.mp4",x="/assets/cases/xiaofangshu/pdf/pc-market-share.png",_="/assets/cases/xiaofangshu/pdf/pc-tax-tool.png",q="/assets/cases/xiaofangshu/pdf/mobile-home.png",P="/assets/cases/xiaofangshu/pdf/mobile-store-analysis.png",y="/assets/cases/xiaofangshu/pdf/mobile-potential.png",A=JSON.parse('{"title":"小房书","description":"","frontmatter":{},"headers":[],"relativePath":"projects/lansi/xiaofangshu-res.md","filePath":"projects/lansi/xiaofangshu-res.md"}'),k={name:"projects/lansi/xiaofangshu-res.md"};function C(v,a,T,w,j,M){return s(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="小房书" tabindex="-1">小房书 <a class="header-anchor" href="#小房书" aria-label="Permalink to &quot;小房书&quot;">​</a></h1><blockquote><p>一个从 2019 年 11 月启动的二手房数据产品化项目。产品面向中小中介门店、夫妻店和个体经纪人，将澜思沉淀的二手房成交数据转化为可购买、可配置、可查询、可辅助经营的门店数据工具。</p></blockquote><h2 id="项目定位" tabindex="-1">项目定位 <a class="header-anchor" href="#项目定位" aria-label="Permalink to &quot;项目定位&quot;">​</a></h2><p>小房书是澜思面向二手房市场推出的轻量化数据产品，服务对象主要是 <span class="text-highlight">中小中介门店、夫妻店和个体经纪人</span>。</p><p>相比面向开发商和专业机构的 CityMap，小房书更贴近一线二手房业务：经纪人需要查真实成交，门店经理需要看主营楼盘和市占位置，中小中介需要用有限预算获得可直接作业的数据能力。</p><p class="highlight-line">项目关键词：<span class="text-highlight">2019 年 11 月启动</span>、<span class="text-highlight-blue">2020 年初约 20 家试用门店</span>、<span class="text-highlight-warm">上百家付费中小中介门店</span>、<span class="text-highlight">二手房数据产品化</span>。</p><p>小房书的核心价值，是把澜思原本沉淀在后台和研究体系中的 <span class="text-highlight-warm">二手房成交数据</span>，转成经纪人和门店能理解、能购买、能使用的数据产品。</p><h2 id="项目背景" tabindex="-1">项目背景 <a class="header-anchor" href="#项目背景" aria-label="Permalink to &quot;项目背景&quot;">​</a></h2><p>二手房经纪业务高度依赖成交信息，但中小中介门店通常缺少稳定、可信、可持续更新的数据工具。</p><p>在实际业务中，经纪人和门店经理常常需要回答这些问题：</p><ul><li>某个楼盘最近真实成交了哪些房源？</li><li>这套房子的成交价格是否有参考依据？</li><li>本店主营楼盘在周边市场中表现如何？</li><li>竞争门店和竞争公司在哪些楼盘更强？</li><li>门店所在板块还有哪些潜在楼盘值得开发？</li><li>经纪人应该优先投入哪些楼盘、哪些户型、哪些价格段？</li></ul><p>大中型平台往往有自己的数据和系统，但中小中介、夫妻店和个体经纪人很难获得同等能力。对他们来说，最有价值的是 <span class="text-highlight">能直接用于带看、议价、拓客、楼盘经营和门店管理的数据</span>。</p><p>小房书要解决的，就是二手房成交数据从“内部数据资产”到“外部可售卖工具”的产品化问题。</p><table tabindex="0"><thead><tr><th>业务问题</th><th>具体表现</th><th>产品机会</th></tr></thead><tbody><tr><td>缺真实成交依据</td><td>经纪人需要用成交明细辅助客户沟通、房东议价和价格判断</td><td>提供楼盘成交、室号级成交、成交公司和历史成交</td></tr><tr><td>门店经营粗放</td><td>中小门店很难判断自己在板块和楼盘中的位置</td><td>提供门店市占率、主营楼盘、视野楼盘和潜在楼盘</td></tr><tr><td>数据购买预算有限</td><td>CityMap 数据级别更高、客单价更高，不适合所有中小门店</td><td>形成轻量化二手房数据产品，和 CityMap 形成产品矩阵互补</td></tr><tr><td>线下作业强依赖人</td><td>经纪人和店长需要在具体楼盘、具体房源、具体客户场景中使用数据</td><td>通过 PC 端和小程序端支持一线作业</td></tr></tbody></table><h2 id="项目目标" tabindex="-1">项目目标 <a class="header-anchor" href="#项目目标" aria-label="Permalink to &quot;项目目标&quot;">​</a></h2><p>项目目标可以拆成三层。</p><p>第一层是 <span class="text-highlight-warm">数据产品化</span>：把二手房成交数据、楼盘数据、成交公司、门店绑定关系和板块信息整理成可售卖的数据产品。</p><p>第二层是 <span class="text-highlight">一线作业工具化</span>：让经纪人能够查成交、看楼盘、做价格判断，帮助门店围绕主营楼盘开展日常作业。</p><p>第三层是 <span class="text-highlight-blue">门店经营管理</span>：在门店拥有绑定楼盘和人员权限后，进一步支持门店市占率、竞争门店、潜在楼盘和经营位置判断。</p><p>对应到产品建设上，核心目标包括：</p><ul><li>将二手房成交数据从后台数据能力转化为可售卖产品。</li><li>通过地图可视化建立 1.0 版本的市场感知，让客户直观看到楼盘和成交数据价值。</li><li>从“按板块售卖”逐步调整为更贴近门店真实作业方式的“按楼盘数据售卖”。</li><li>支持门店经理和经纪人的人员权限、数据权限和楼盘配置。</li><li>通过 PC 端和小程序端覆盖门店管理、楼盘查询、板块行情和经纪人作业场景。</li><li>让小房书与 CityMap 形成产品矩阵：CityMap 服务高客单价重决策，小房书服务轻量化作业和中小门店覆盖。</li></ul><h2 id="我的角色" tabindex="-1">我的角色 <a class="header-anchor" href="#我的角色" aria-label="Permalink to &quot;我的角色&quot;">​</a></h2><p>在小房书项目中，我承担核心产品角色，主导了 <span class="text-highlight-warm">产品原型设计、线下门店调研、客户沟通、数据口径设计、PC 端和小程序端产品规划</span>。</p><p>我的工作主要包括：</p><table tabindex="0"><thead><tr><th>工作方向</th><th>我负责的内容</th></tr></thead><tbody><tr><td>产品定位</td><td>将小房书定位为面向中小中介门店和经纪人的二手房数据产品</td></tr><tr><td>线下调研</td><td>和商务一起走访线下中介门店，访谈店长、经纪人和中小中介客户</td></tr><tr><td>需求转化</td><td>将“查真实成交、看具体室号、看成交公司、管主营楼盘”等一线需求转成产品功能</td></tr><tr><td>1.0 原型设计</td><td>设计地图可视化、楼盘成交、成交查询等能力，让客户直观看到二手房数据价值</td></tr><tr><td>2.0 产品迭代</td><td>主导门店经理 / 经纪人权限、人员配置、楼盘配置、数据权限分级和门店市占能力设计</td></tr><tr><td>数据口径</td><td>梳理二手房成交、楼盘、板块、门店、市占率、成交公司等对象关系和指标口径</td></tr><tr><td>PC 与小程序</td><td>规划 PC 端门店管理能力和小程序端经纪人作业场景</td></tr><tr><td>客户反馈</td><td>根据试用门店和付费客户反馈，持续调整售卖颗粒度、权限体系和作业工具设计</td></tr></tbody></table><p>这个项目对我的要求，远超过原型设计本身，需要在商业化、客户调研、数据口径、产品结构和交付方式之间反复拉通。</p><h2 id="我的核心贡献" tabindex="-1">我的核心贡献 <a class="header-anchor" href="#我的核心贡献" aria-label="Permalink to &quot;我的核心贡献&quot;">​</a></h2><table tabindex="0"><thead><tr><th>贡献类型</th><th>具体贡献</th><th>价值</th></tr></thead><tbody><tr><td>数据商业化</td><td>将澜思二手房成交数据包装成可售卖的轻量产品</td><td>拓展 CityMap 之外的中小中介客户市场</td></tr><tr><td>用户洞察</td><td>通过线下门店调研识别真实需求</td><td>将产品重点从板块数据转向门店真正需要的楼盘数据</td></tr><tr><td>产品策略</td><td>推动从“按板块售卖”调整为“按楼盘数据售卖”</td><td>更贴近中小门店主营楼盘的经营方式</td></tr><tr><td>权限体系</td><td>设计门店经理、经纪人、人员配置和数据权限分级</td><td>支撑多门店、多角色、多数据范围的商业交付</td></tr><tr><td>经营分析</td><td>将门店绑定数据转化为市占率、潜在楼盘和竞争位置判断</td><td>让产品从查数据升级为门店经营工具</td></tr></tbody></table><h2 id="建设过程" tabindex="-1">建设过程 <a class="header-anchor" href="#建设过程" aria-label="Permalink to &quot;建设过程&quot;">​</a></h2><h3 id="_1-2019-年-11-月-从二手房成交数据产品化开始" tabindex="-1">1. 2019 年 11 月：从二手房成交数据产品化开始 <a class="header-anchor" href="#_1-2019-年-11-月-从二手房成交数据产品化开始" aria-label="Permalink to &quot;1. 2019 年 11 月：从二手房成交数据产品化开始&quot;">​</a></h3><p>小房书从 2019 年 11 月启动。项目最初的切入点，是把澜思已有的二手房成交数据，用更直观的方式呈现给经纪人和中小门店。</p><p>1.0 阶段的重点，是先让市场看到数据的价值。二手房楼盘在地图上呈现，结合成交数据、楼盘位置和区域信息，让客户第一眼感受到“这套数据能看、能查、能辅助业务判断”。</p><p>这一阶段的产品重点包括：</p><ul><li>楼盘地图可视化。</li><li>二手房成交数据展示。</li><li>楼盘成交和区域分布。</li><li>基础成交查询能力。</li><li>让客户理解澜思二手房数据的差异化价值。</li></ul><h3 id="_2-2020-年初-约-20-家试用门店验证" tabindex="-1">2. 2020 年初：约 20 家试用门店验证 <a class="header-anchor" href="#_2-2020-年初-约-20-家试用门店验证" aria-label="Permalink to &quot;2. 2020 年初：约 20 家试用门店验证&quot;">​</a></h3><p>2020 年初，小房书已经有约 <span class="text-highlight-blue">20 家试用门店</span>。这些试用门店帮助产品验证了一件很重要的事：中小中介确实愿意为二手房成交数据付费，他们更关心和自己日常作业强相关的楼盘数据。</p><p>线下调研中，门店和经纪人的需求集中在几类：</p><ul><li>真实成交价和具体成交明细。</li><li>具体地址、楼栋、室号、面积、户型。</li><li>成交公司和竞争公司。</li><li>近一年或近几年的历史成交。</li><li>主营楼盘和周边楼盘。</li><li>可导出、可查询、可在移动端使用。</li><li>价格判断、税费计算、核税价参考等作业工具。</li></ul><p>这些反馈推动产品从“展示数据”转向“服务门店作业”。</p><h3 id="_3-2020-年疫情-线下拓展放缓-但需求更明确" tabindex="-1">3. 2020 年疫情：线下拓展放缓，但需求更明确 <a class="header-anchor" href="#_3-2020-年疫情-线下拓展放缓-但需求更明确" aria-label="Permalink to &quot;3. 2020 年疫情：线下拓展放缓，但需求更明确&quot;">​</a></h3><p>2020 年疫情对线下门店调研、销售拓展和客户交付节奏产生了影响。中介门店的线下经营受到冲击，项目推进节奏也因此放缓。</p><p>这个阶段也让产品方向更加明确：小房书需要在数据地图之外，继续解决门店真实使用中的权限、配置、售卖颗粒度和作业效率问题。</p><p>因此，2020 年下半年继续推进 2.0 版本迭代，重点从地图可视化和成交查询，升级到门店权限、经纪人权限、楼盘配置、数据权限分级和市占率分析。</p><h3 id="_4-从板块售卖转向楼盘数据售卖" tabindex="-1">4. 从板块售卖转向楼盘数据售卖 <a class="header-anchor" href="#_4-从板块售卖转向楼盘数据售卖" aria-label="Permalink to &quot;4. 从板块售卖转向楼盘数据售卖&quot;">​</a></h3><p>小房书早期曾以板块为售卖和配置颗粒度，但在调研和试用中发现，中小门店并不一定需要整个板块的数据。</p><p>门店有自己的主营楼盘，也有视野楼盘。经纪人每天真正作业的对象，通常是几个熟悉的小区、周边竞争楼盘，以及可能开发的潜在楼盘。</p><p>因此，产品策略从 <span class="text-highlight-warm">按板块售卖</span> 逐渐调整为 <span class="text-highlight">按楼盘数据售卖</span>。</p><p>这个调整很关键，因为它让产品更贴近客户的付费逻辑：</p><ul><li>门店愿意为自己经营的主营楼盘付费。</li><li>经纪人更关心具体楼盘和具体成交。</li><li>中小门店不需要承担过重的数据购买成本。</li><li>楼盘配置可以进一步支撑权限、人员和市占分析。</li></ul><h3 id="_5-2-0-权限配置、门店经营和小程序作业" tabindex="-1">5. 2.0：权限配置、门店经营和小程序作业 <a class="header-anchor" href="#_5-2-0-权限配置、门店经营和小程序作业" aria-label="Permalink to &quot;5. 2.0：权限配置、门店经营和小程序作业&quot;">​</a></h3><p>2.0 版本的重点，是把小房书从“成交数据查询工具”升级为“门店经营和经纪人作业工具”。</p><p>关键变化包括：</p><table tabindex="0"><thead><tr><th>能力</th><th>1.0 阶段</th><th>2.0 阶段</th></tr></thead><tbody><tr><td>数据展示</td><td>地图上展示二手房楼盘和成交数据</td><td>结合门店、楼盘、人员、权限进行分层展示</td></tr><tr><td>售卖颗粒度</td><td>以板块为主</td><td>更强调楼盘数据、主营楼盘和视野楼盘</td></tr><tr><td>用户角色</td><td>经纪人和门店使用为主</td><td>增加门店经理、经纪人、人员配置和权限分级</td></tr><tr><td>数据权限</td><td>相对粗颗粒度</td><td>按门店、人员、楼盘、数据范围进行控制</td></tr><tr><td>经营分析</td><td>以查询和展示为主</td><td>增加门店市占率、竞争位置、潜在楼盘判断</td></tr><tr><td>使用终端</td><td>PC 端为主</td><td>PC 端 + 小程序端，覆盖门店管理和一线作业</td></tr></tbody></table><p>2.0 的产品模块包括：</p><ul><li>门店管理。</li><li>楼盘配置。</li><li>板块行情。</li><li>门店市占率。</li><li>经纪人 / 门店人员配置。</li><li>数据权限分级。</li><li>一键查成交。</li><li>核税价参考。</li><li>税费计算器。</li><li>小程序端经纪人作业入口。</li></ul><h3 id="_6-2021-年后-行业下行中的产品节奏变化" tabindex="-1">6. 2021 年后：行业下行中的产品节奏变化 <a class="header-anchor" href="#_6-2021-年后-行业下行中的产品节奏变化" aria-label="Permalink to &quot;6. 2021 年后：行业下行中的产品节奏变化&quot;">​</a></h3><p>2021 年后，房地产行业整体进入下行周期，二手房市场活跃度和中小中介付费能力也受到影响。小房书后续迭代节奏随行业环境逐渐放缓。</p><p>这并不意味着产品价值消失。相反，小房书在 2019-2020 年完成了从数据资产到产品商业化的验证，并在后续服务了 <span class="text-highlight-warm">上百家付费中小中介门店</span>。</p><p>其中一部分客户直接购买小房书，一部分客户通过购买更高客单价的 CityMap 获得小房书权益。这样的组合交付，也体现了澜思房地产数据产品矩阵的分层能力：</p><ul><li>CityMap：面向开发商和专业机构，数据级别更高，服务城市研究和投资决策。</li><li>小房书：面向中小中介和经纪人，更轻量，服务二手房作业和门店经营。</li></ul><h2 id="核心模块设计" tabindex="-1">核心模块设计 <a class="header-anchor" href="#核心模块设计" aria-label="Permalink to &quot;核心模块设计&quot;">​</a></h2><h3 id="楼盘地图与成交展示" tabindex="-1">楼盘地图与成交展示 <a class="header-anchor" href="#楼盘地图与成交展示" aria-label="Permalink to &quot;楼盘地图与成交展示&quot;">​</a></h3><p>1.0 阶段通过地图呈现二手房楼盘和成交数据，让客户直观看到楼盘分布、成交热度和区域市场。</p><p>这个模块的价值，是先建立市场感知。对中小中介来说，地图上的楼盘点位和成交表现，比传统表格更容易产生“这个数据可以帮我做业务”的感受。</p><h3 id="楼盘数据与主营楼盘" tabindex="-1">楼盘数据与主营楼盘 <a class="header-anchor" href="#楼盘数据与主营楼盘" aria-label="Permalink to &quot;楼盘数据与主营楼盘&quot;">​</a></h3><p>2.0 阶段强化了楼盘配置能力。门店可以围绕自己的主营楼盘和视野楼盘使用数据，购买颗粒度也因此更贴近真实经营范围。</p><p>主营楼盘是经纪人日常作业的核心对象。围绕主营楼盘，产品可以进一步提供成交明细、历史成交、成交公司、价格段、户型和周边竞争情况。</p><h3 id="门店与人员权限" tabindex="-1">门店与人员权限 <a class="header-anchor" href="#门店与人员权限" aria-label="Permalink to &quot;门店与人员权限&quot;">​</a></h3><p>小房书服务的是中小中介门店，不同角色对数据的需求不同。</p><p>门店经理需要看到门店整体经营情况，经纪人需要看到自己可作业的楼盘和成交数据。因此，2.0 版本设计了门店经理、经纪人、人员配置和数据权限分级。</p><p>这套权限体系让小房书从单人查询工具，升级为可交付给门店组织使用的数据产品。</p><h3 id="门店市占率" tabindex="-1">门店市占率 <a class="header-anchor" href="#门店市占率" aria-label="Permalink to &quot;门店市占率&quot;">​</a></h3><p>当系统有了门店、人员和楼盘绑定关系后，就可以进一步计算门店在板块或楼盘中的市场位置。</p><p>门店市占率帮助店长判断：</p><ul><li>自己门店在板块中处于什么位置。</li><li>哪些主营楼盘表现强。</li><li>哪些潜在楼盘值得开发。</li><li>周边竞争门店和竞争公司在哪些楼盘更强。</li></ul><p>这让小房书从“查成交”进一步升级为“看经营”。</p><h3 id="一键查成交与作业工具" tabindex="-1">一键查成交与作业工具 <a class="header-anchor" href="#一键查成交与作业工具" aria-label="Permalink to &quot;一键查成交与作业工具&quot;">​</a></h3><p>经纪人最直接的需求，是快速查询某个楼盘、某个室号或某类房源的真实成交记录。</p><p>围绕这一需求，小房书规划了一键查成交、核税价参考、税费计算器等作业工具，让成交数据能够进入日常带看、议价、合同和客户沟通场景。</p><h2 id="核心功能演示" tabindex="-1">核心功能演示 <a class="header-anchor" href="#核心功能演示" aria-label="Permalink to &quot;核心功能演示&quot;">​</a></h2>',80),t("section",{class:"case-demo-grid"},[t("figure",null,[t("video",{autoplay:"",muted:"",loop:"",playsinline:"",preload:"metadata",poster:r},[t("source",{src:p,type:"video/mp4"})]),t("figcaption",null,[t("strong",null,"成交公司与竞争公司配置"),t("span",null,"对应门店市占率和竞争分析的基础口径，先明确本门店、竞争公司和成交归属，后续才能计算本公司成交、竞争公司成交和板块市占。")])]),t("figure",null,[t("video",{autoplay:"",muted:"",loop:"",playsinline:"",preload:"metadata",poster:o},[t("source",{src:d,type:"video/mp4"})]),t("figcaption",null,[t("strong",null,"门店人员与权限配置"),t("span",null,"对应 2.0 阶段的门店经理、经纪人、人员配置和数据权限分级，支撑产品从单人查询工具升级为门店组织可用的 B 端产品。")])]),t("figure",null,[t("video",{autoplay:"",muted:"",loop:"",playsinline:"",preload:"metadata",poster:n},[t("source",{src:h,type:"video/mp4"})]),t("figcaption",null,[t("strong",null,"单个楼盘配置"),t("span",null,"对应从板块售卖转向楼盘数据售卖的关键变化，让门店可以围绕主营楼盘购买和使用数据，贴近真实经营半径。")])]),t("figure",null,[t("video",{autoplay:"",muted:"",loop:"",playsinline:"",preload:"metadata",poster:c},[t("source",{src:u,type:"video/mp4"})]),t("figcaption",null,[t("strong",null,"楼盘属性切换"),t("span",null,"对应主营楼盘、视野楼盘和恒星楼盘的分类管理，让门店可以持续调整经营重点，并把楼盘属性用于后续市占和潜在楼盘判断。")])]),t("figure",null,[t("video",{autoplay:"",muted:"",loop:"",playsinline:"",preload:"metadata",poster:g},[t("source",{src:b,type:"video/mp4"})]),t("figcaption",null,[t("strong",null,"批量上传楼盘表格"),t("span",null,"对应中小门店真实交付中的批量初始化场景，支持从门店已有楼盘清单快速进入系统配置，降低上线和试用成本。")])]),t("figure",null,[t("video",{autoplay:"",muted:"",loop:"",playsinline:"",preload:"metadata",poster:m},[t("source",{src:f,type:"video/mp4"})]),t("figcaption",null,[t("strong",null,"视野楼盘圈选配置"),t("span",null,"对应门店经营中的视野楼盘和潜在楼盘分析，帮助店长判断周边机会、竞争位置和后续开发方向。")])])],-1),i('<h2 id="关键数据页面" tabindex="-1">关键数据页面 <a class="header-anchor" href="#关键数据页面" aria-label="Permalink to &quot;关键数据页面&quot;">​</a></h2><p>这些页面展示的是小房书 2.0 的核心产品形态：PC 端负责门店配置、楼盘管理和经营分析，小程序端承接经纪人和店长的移动作业场景。</p><section class="case-image-grid"><figure><img src="'+x+'" alt="小房书 PC 端门店市占率与主营楼盘分析页面"><figcaption><strong>PC 端门店市占率与主营楼盘分析</strong><span>把门店、主营楼盘、板块、成交公司和地图范围放在同一页面，支持店长查看板块市占率走势、主营楼盘成交占比和周边竞争门店。</span></figcaption></figure><figure><img src="'+_+'" alt="小房书 PC 端税费计算与一键查成交工具页面"><figcaption><strong>PC 端作业工具</strong><span>一键查成交、核税价参考和税费计算器把成交数据带入经纪人日常作业，帮助议价、税费测算和客户沟通。</span></figcaption></figure></section><section class="case-mobile-grid"><figure><img src="'+q+'" alt="小房书小程序首页数据看板"><figcaption><strong>移动端首页</strong><span>集中展示门店市占率、潜在热门楼盘、周边竞争门店、板块行情和楼盘行情。</span></figcaption></figure><figure><img src="'+P+'" alt="小房书小程序门店主营楼盘分析"><figcaption><strong>门店主营楼盘分析</strong><span>以板块市占率走势、主营楼盘市占率和成交占比，帮助店长判断门店经营重点。</span></figcaption></figure><figure><img src="'+y+`" alt="小房书小程序潜在楼盘分析"><figcaption><strong>潜在楼盘分析</strong><span>通过视野楼盘成交表现识别潜在机会，提示门店调整楼盘经营策略。</span></figcaption></figure></section><h2 id="数据如何驱动产品" tabindex="-1">数据如何驱动产品 <a class="header-anchor" href="#数据如何驱动产品" aria-label="Permalink to &quot;数据如何驱动产品&quot;">​</a></h2><p>小房书的底层逻辑可以概括为：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>二手房成交数据 + 楼盘数据 + 门店绑定 + 经纪人权限 + 成交公司 + 市占口径</span></span>
<span class="line"><span>= 可售卖、可配置、可作业的二手房数据产品</span></span></code></pre></div><p>在这个项目中，数据就是产品本体。</p><h3 id="_1-成交数据决定产品价值" tabindex="-1">1. 成交数据决定产品价值 <a class="header-anchor" href="#_1-成交数据决定产品价值" aria-label="Permalink to &quot;1. 成交数据决定产品价值&quot;">​</a></h3><p>中小中介最关心的是能否看到真实成交。成交总价、成交均价、成交时间、楼栋室号、成交公司、户型面积等字段，直接影响经纪人与客户沟通时的可信度。</p><p>如果成交数据只能停留在内部分析表中，就无法形成商业价值。小房书的价值，是把这些成交数据变成客户可购买、可查询、可复用的产品能力。</p><h3 id="_2-楼盘颗粒度决定售卖方式" tabindex="-1">2. 楼盘颗粒度决定售卖方式 <a class="header-anchor" href="#_2-楼盘颗粒度决定售卖方式" aria-label="Permalink to &quot;2. 楼盘颗粒度决定售卖方式&quot;">​</a></h3><p>板块数据看起来完整，但对中小门店来说颗粒度偏大。门店真正经营的是主营楼盘和周边视野楼盘。</p><p>因此，小房书将数据使用和售卖颗粒度逐渐收敛到楼盘，让客户为自己真正需要的楼盘数据付费。</p><h3 id="_3-权限关系决定交付能力" tabindex="-1">3. 权限关系决定交付能力 <a class="header-anchor" href="#_3-权限关系决定交付能力" aria-label="Permalink to &quot;3. 权限关系决定交付能力&quot;">​</a></h3><p>如果一个产品只给单个用户使用，权限设计可以很简单。但小房书要服务门店，必须处理门店经理、经纪人、人员配置、楼盘配置和数据可见范围。</p><p>这套权限关系决定了产品能否从单点工具变成可规模交付的 B 端产品。</p><h3 id="_4-门店数据决定经营分析" tabindex="-1">4. 门店数据决定经营分析 <a class="header-anchor" href="#_4-门店数据决定经营分析" aria-label="Permalink to &quot;4. 门店数据决定经营分析&quot;">​</a></h3><p>当系统知道一个门店绑定了哪些楼盘、有哪些经纪人、覆盖哪些板块，就可以进一步做门店市占率、潜在楼盘和竞争门店分析。</p><p>这也是小房书从“成交查询工具”升级为“门店经营工具”的关键。</p><h2 id="项目成果" tabindex="-1">项目成果 <a class="header-anchor" href="#项目成果" aria-label="Permalink to &quot;项目成果&quot;">​</a></h2><p>这个项目的成果可以从产品、商业、数据和个人能力四个角度看。</p><h3 id="产品成果" tabindex="-1">产品成果 <a class="header-anchor" href="#产品成果" aria-label="Permalink to &quot;产品成果&quot;">​</a></h3><ul><li>完成小房书 1.0 从 0 到 1 的产品验证，用地图可视化呈现二手房楼盘和成交数据。</li><li>在 2020 年初获得约 <span class="text-highlight-blue">20 家试用门店</span>，验证中小中介对二手房成交数据的真实需求。</li><li>推进小房书 2.0 迭代，完成门店经理 / 经纪人权限、人员配置、楼盘配置、数据权限分级和门店市占率等能力设计。</li><li>规划 PC 端和小程序端，让产品覆盖门店管理和经纪人一线作业。</li><li>沉淀一键查成交、核税价参考、税费计算器等作业工具方向。</li></ul><h3 id="商业成果" tabindex="-1">商业成果 <a class="header-anchor" href="#商业成果" aria-label="Permalink to &quot;商业成果&quot;">​</a></h3><ul><li>小房书后续服务 <span class="text-highlight-warm">上百家付费中小中介门店</span>。</li><li>形成轻量化二手房数据产品，与高客单价 CityMap 形成组合交付。</li><li>支持部分 CityMap 客户获得小房书权益，提升澜思房地产数据产品矩阵的交付完整度。</li><li>将澜思二手房成交数据从内部能力转化为可售卖、可配置、可交付的数据产品。</li></ul><h3 id="数据成果" tabindex="-1">数据成果 <a class="header-anchor" href="#数据成果" aria-label="Permalink to &quot;数据成果&quot;">​</a></h3><ul><li>梳理二手房成交、楼盘、板块、门店、人员、成交公司、市占率等核心数据对象。</li><li>将板块数据、楼盘数据、门店绑定关系和人员权限结合起来，形成可交付的数据权限体系。</li><li>通过主营楼盘和视野楼盘配置，让数据使用颗粒度更贴近中小门店的真实经营方式。</li><li>将成交数据延展到市占分析、潜在楼盘判断和经纪人作业工具中。</li></ul><h3 id="个人能力沉淀" tabindex="-1">个人能力沉淀 <a class="header-anchor" href="#个人能力沉淀" aria-label="Permalink to &quot;个人能力沉淀&quot;">​</a></h3><p>这个项目让我更直接地理解了数据产品商业化的难点：数据本身有价值，但只有进入具体业务场景、匹配客户付费方式、解决真实作业问题，才能形成产品价值。</p><p>我在项目中沉淀了几类能力：</p><ul><li><span class="text-highlight-warm">线下用户调研能力</span>：和商务一起走访门店，从一线经纪人和店长反馈中识别真实需求。</li><li><span class="text-highlight">数据产品化能力</span>：把二手房成交数据转成地图、查询、市占、权限和作业工具。</li><li><span class="text-highlight-blue">商业化判断能力</span>：从板块售卖调整为楼盘数据售卖，让产品更贴近客户付费意愿。</li><li><span class="text-highlight">B 端权限设计能力</span>：围绕门店、人员、楼盘和数据范围设计权限分级。</li><li><span class="text-highlight-warm">行业周期理解能力</span>：在疫情和房地产下行周期中理解产品节奏与行业环境的关系。</li></ul><h2 id="为什么这个项目能体现我的优势" tabindex="-1">为什么这个项目能体现我的优势 <a class="header-anchor" href="#为什么这个项目能体现我的优势" aria-label="Permalink to &quot;为什么这个项目能体现我的优势&quot;">​</a></h2><p>小房书最能体现我的地方，是我能够把一套沉淀在后台的房地产成交数据，转成真实客户愿意付费使用的产品。</p><p>这个项目同时体现了几个能力层级：</p><table tabindex="0"><thead><tr><th>能力层级</th><th>在小房书中的体现</th></tr></thead><tbody><tr><td>用户理解</td><td>理解中小中介、夫妻店、个体经纪人的真实作业方式和付费能力</td></tr><tr><td>数据理解</td><td>能识别二手房成交数据、楼盘数据、门店数据、市占口径之间的关系</td></tr><tr><td>产品抽象</td><td>能把成交数据拆成地图、楼盘、权限、门店、市占和作业工具</td></tr><tr><td>商业化落地</td><td>能根据客户使用场景调整售卖颗粒度和交付方式</td></tr><tr><td>行业判断</td><td>能理解疫情、二手房市场下行和房地产周期对产品节奏的影响</td></tr></tbody></table><p>如果用一句话总结这个项目：我主导小房书从 0 到 1 的产品原型、线下调研、数据口径、PC 与小程序规划，并推动它从二手房成交数据展示，升级为服务中小中介门店经营和经纪人作业的轻量化数据产品。</p>`,37)])])}const B=l(k,[["render",C]]);export{A as __pageData,B as default};
